#### 广度优先

```js
// 非递归方式
const BFS = (tree) => {
  let list = [];
  if (tree !== null) {
    // 借用队列实现，队列先进先出，借用数组模拟队列
    let queue = [];
    queue.unshift(tree);
    while (queue.length !== 0) {
      let item = queue.shift();
      list.push(item);
      let children = item.children;
      if (children) {
        for (let i = 0; i < children.length; i++) {
          queue.push(children[i]);
        }
      }
    }
  }
  return list;
};

let array2 = BFS(tree);
console.log(array2, "array2");
